import java.io.*;

public class CommandInjectionExample {
    public static void main(String[] args) {
        try {
            // Simulating user input
            String userInput = "ls /tmp";

            // Sanitize user input to allow only whitelisted characters (e.g., alphanumeric and certain symbols)
            if (!userInput.matches("[a-zA-Z0-9_/\\s]+")) {
                throw new IllegalArgumentException("Invalid input");
            }

            // Safe command execution using ProcessBuilder
            ProcessBuilder pb = new ProcessBuilder("ls", userInput);
            pb.redirectErrorStream(true);
            Process proc = pb.start();

            BufferedReader stdInput = new BufferedReader(new InputStreamReader(proc.getInputStream()));

            String output;
            while ((output = stdInput.readLine()) != null) {
                System.out.println(output);
            }
        } catch (IOException | IllegalArgumentException e) {
            e.printStackTrace();
        }
    }
}

